68: func NewTag(filePath string, fileInfo os.FileInfo, tags ParsedTags) Tags {
69: 	for t, values := range tags {
70: 		values = removeDuplicatesAndEmpty(values)
71: 		if len(values) == 0 {
72: 			delete(tags, t)
73: 			continue
74: 		}
75: 		tags[t] = values
76: 	}
77: 	return Tags{
78: 		filePath: filePath,
79: 		fileInfo: fileInfo,
80: 		Tags:     tags,
81: 	}
82: }
