324: var dateRegex = regexp.MustCompile(`([12]\d\d\d)`)
325: 
326: func (t Tags) getDate(tagNames ...string) (int, string) {
327: 	tag := t.getFirstTagValue(tagNames...)
328: 	if len(tag) < 4 {
329: 		return 0, ""
330: 	}
331: 	// first get just the year
332: 	match := dateRegex.FindStringSubmatch(tag)
333: 	if len(match) == 0 {
334: 		log.Warn("Error parsing "+tagNames[0]+" field for year", "file", t.filePath, "date", tag)
335: 		return 0, ""
336: 	}
337: 	year, _ := strconv.Atoi(match[1])
338: 
339: 	if len(tag) < 5 {
340: 		return year, match[1]
341: 	}
342: 
343: 	//then try YYYY-MM-DD
344: 	if len(tag) > 10 {
345: 		tag = tag[:10]
346: 	}
347: 	layout := "2006-01-02"
348: 	_, err := time.Parse(layout, tag)
349: 	if err != nil {
350: 		layout = "2006-01"
351: 		_, err = time.Parse(layout, tag)
352: 		if err != nil {
353: 			log.Warn("Error parsing "+tagNames[0]+" field for month + day", "file", t.filePath, "date", tag)
354: 			return year, match[1]
355: 		}
356: 	}
357: 	return year, tag
358: }
