// mockCacheWarmer is a no-op implementation for testing
type mockCacheWarmer struct{}

func (m *mockCacheWarmer) PreCache(artwork.ArtworkID) {}

// TestFullScanWithFixtures tests a complete scan of a directory with real audio files
func TestFullScanWithFixtures(t *testing.T) {
	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedAlbum = albumRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	changeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	if changeCount == 0 {
		t.Errorf("Expected changes to be detected, got 0")
	}

	// Verify media files were created
	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	if len(mediaFiles) == 0 {
		t.Errorf("Expected media files to be created, got 0")
	}

	// Verify at least one media file has proper metadata
	found := false
	for _, mf := range mediaFiles {
		if mf.Title != "" || mf.Artist != "" {
			found = true
			break
		}
	}

	if !found {
		t.Errorf("Expected at least one media file to have metadata extracted")
	}
}

// TestMetadataExtraction tests that metadata is correctly extracted from audio files
func TestMetadataExtraction(t *testing.T) {
	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Metadata Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	if len(mediaFiles) == 0 {
		t.Fatalf("Expected media files to be created")
	}

	// Check that at least some files have extracted metadata
	filesWithMetadata := 0
	for _, mf := range mediaFiles {
		if mf.Path != "" && mf.Suffix != "" {
			filesWithMetadata++
			// Verify file suffix is correct
			expectedSuffix := filepath.Ext(mf.Path)
			if expectedSuffix != "" {
				expectedSuffix = expectedSuffix[1:] // Remove the dot
			}
			if mf.Suffix != "" && mf.Suffix != expectedSuffix {
				t.Logf("Suffix mismatch for %s: expected %s, got %s", mf.Path, expectedSuffix, mf.Suffix)
			}
		}
	}

	if filesWithMetadata == 0 {
		t.Errorf("Expected files to have metadata extracted with path and suffix")
	}
}

