package scanner

import (
	"context"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/navidrome/navidrome/model"
	"github.com/navidrome/navidrome/tests"
)

// mockCacheWarmer is a no-op implementation for testing
type mockCacheWarmer struct{}

// PreCache implements artwork.CacheWarmer interface
func (m *mockCacheWarmer) PreCache(id interface{}) {}

// TestFullScanWithFixtures tests a complete scan of a directory with real audio files
func TestFullScanWithFixtures(t *testing.T) {
	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedAlbum = albumRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	changeCount, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	if changeCount == 0 {
		t.Errorf("Expected changes to be detected, got 0")
	}

	// Verify media files were created
	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	if len(mediaFiles) == 0 {
		t.Errorf("Expected media files to be created, got 0")
	}

	// Verify at least one media file has proper metadata
	found := false
	for _, mf := range mediaFiles {
		if mf.Title != "" || mf.Artist != "" {
			found = true
			break
		}
	}

	if !found {
		t.Errorf("Expected at least one media file to have metadata extracted")
	}
}

// TestMetadataExtraction tests that metadata is correctly extracted from audio files
func TestMetadataExtraction(t *testing.T) {
	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Metadata Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	if len(mediaFiles) == 0 {
		t.Fatalf("Expected media files to be created")
	}

	// Check that at least some files have extracted metadata
	filesWithMetadata := 0
	for _, mf := range mediaFiles {
		if mf.Path != "" && mf.Suffix != "" {
			filesWithMetadata++
			// Verify file suffix is correct
			expectedSuffix := filepath.Ext(mf.Path)
			if expectedSuffix != "" {
				expectedSuffix = expectedSuffix[1:] // Remove the dot
			}
			if mf.Suffix != "" && mf.Suffix != expectedSuffix {
				t.Logf("Suffix mismatch for %s: expected %s, got %s", mf.Path, expectedSuffix, mf.Suffix)
			}
		}
	}

	if filesWithMetadata == 0 {
		t.Errorf("Expected files to have metadata extracted with path and suffix")
	}
}

// TestAlbumCreation tests that albums are created from scanned media files
func TestAlbumCreation(t *testing.T) {
	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	albumRepo := tests.CreateMockAlbumRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedAlbum = albumRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Album Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	_, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	// Albums should be created through the refresher
	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	// Collect all unique album IDs
	albumIDs := make(map[string]bool)
	for _, mf := range mediaFiles {
		if mf.AlbumID != "" {
			albumIDs[mf.AlbumID] = true
		}
	}

	if len(albumIDs) == 0 {
		t.Logf("No albums with IDs found (this may be expected for fixture files)")
	}
}

// TestIncrementalScan tests that re-scanning with no changes produces no updates
func TestIncrementalScan(t *testing.T) {
	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Incremental Test Library",
		Path:       "tests/fixtures",
		LastScanAt: time.Now().Add(-24 * time.Hour), // Recent scan
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	// First scan
	changeCount1, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("First scan failed: %v", err)
	}

	if changeCount1 == 0 {
		t.Fatalf("First scan should detect changes")
	}

	// Get initial media files
	initialFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get initial media files: %v", err)
	}

	// Second scan without changes
	lib.LastScanAt = time.Now().Add(-1 * time.Second) // Just scanned
	scanner2 := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress2 := make(chan uint32, 100)

	changeCount2, err := scanner2.Scan(ctx, lib, false, progress2)
	close(progress2)

	if err != nil {
		t.Fatalf("Second scan failed: %v", err)
	}

	// No changes should be detected since LastScanAt is recent
	if changeCount2 != 0 {
		t.Logf("Second scan detected %d changes (expected 0 since recent scan)", changeCount2)
	}

	// Verify same number of files
	finalFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get final media files: %v", err)
	}

	if len(initialFiles) != len(finalFiles) {
		t.Errorf("Expected same number of files after incremental scan: initial=%d, final=%d",
			len(initialFiles), len(finalFiles))
	}
}

// TestFileDeletion tests that deleted files are removed from database
func TestFileDeletion(t *testing.T) {
	// This test creates a temporary directory with test files
	tempDir, err := os.MkdirTemp("", "scanner_test_*")
	if err != nil {
		t.Fatalf("Failed to create temp directory: %v", err)
	}
	defer os.RemoveAll(tempDir)

	// Create a test file by copying from fixtures
	fixtureFile := "tests/fixtures/test.mp3"
	testFile := filepath.Join(tempDir, "test.mp3")

	srcFile, err := os.Open(fixtureFile)
	if err != nil {
		t.Skipf("Could not open fixture file: %v (skipping deletion test)", err)
	}
	defer srcFile.Close()

	dstFile, err := os.Create(testFile)
	if err != nil {
		t.Fatalf("Failed to create test file: %v", err)
	}
	defer dstFile.Close()

	if _, err := dstFile.ReadFrom(srcFile); err != nil {
		t.Fatalf("Failed to copy test file: %v", err)
	}

	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Deletion Test Library",
		Path:       tempDir,
		LastScanAt: time.Time{},
	}

	// First scan - file exists
	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	changeCount1, err := scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("First scan failed: %v", err)
	}

	if changeCount1 == 0 {
		t.Errorf("Expected changes to be detected on first scan")
	}

	filesAfterFirstScan, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files after first scan: %v", err)
	}

	if len(filesAfterFirstScan) == 0 {
		t.Fatalf("Expected media files to be created in first scan")
	}

	// Delete the file
	if err := os.Remove(testFile); err != nil {
		t.Fatalf("Failed to delete test file: %v", err)
	}

	// Second scan - file is gone
	lib.LastScanAt = time.Time{} // Reset to allow detection of changes
	scanner2 := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress2 := make(chan uint32, 100)

	changeCount2, err := scanner2.Scan(ctx, lib, true, progress2)
	close(progress2)

	if err != nil {
		t.Fatalf("Second scan failed: %v", err)
	}

	filesAfterSecondScan, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files after second scan: %v", err)
	}

	// Should have fewer files or none since we deleted the file
	if len(filesAfterSecondScan) > len(filesAfterFirstScan) {
		t.Errorf("Expected same or fewer files after deletion: before=%d, after=%d",
			len(filesAfterFirstScan), len(filesAfterSecondScan))
	}
}

// TestEmptyDirectory tests scanning an empty directory
func TestEmptyDirectory(t *testing.T) {
	tempDir, err := os.MkdirTemp("", "scanner_empty_*")
	if err != nil {
		t.Fatalf("Failed to create temp directory: %v", err)
	}
	defer os.RemoveAll(tempDir)

	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Empty Test Library",
		Path:       tempDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	_, err = scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan of empty directory failed: %v", err)
	}

	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	if len(mediaFiles) != 0 {
		t.Errorf("Expected no media files from empty directory, got %d", len(mediaFiles))
	}
}

// TestScanWithNestedDirectories tests scanning nested directory structure
func TestScanWithNestedDirectories(t *testing.T) {
	tempDir, err := os.MkdirTemp("", "scanner_nested_*")
	if err != nil {
		t.Fatalf("Failed to create temp directory: %v", err)
	}
	defer os.RemoveAll(tempDir)

	// Create nested directory structure
	nestedDir := filepath.Join(tempDir, "artist", "album")
	if err := os.MkdirAll(nestedDir, 0755); err != nil {
		t.Fatalf("Failed to create nested directories: %v", err)
	}

	// Copy a test file to nested directory
	fixtureFile := "tests/fixtures/test.mp3"
	testFile := filepath.Join(nestedDir, "test.mp3")

	srcFile, err := os.Open(fixtureFile)
	if err != nil {
		t.Skipf("Could not open fixture file: %v (skipping nested dir test)", err)
	}
	defer srcFile.Close()

	dstFile, err := os.Create(testFile)
	if err != nil {
		t.Fatalf("Failed to create test file: %v", err)
	}
	defer dstFile.Close()

	if _, err := dstFile.ReadFrom(srcFile); err != nil {
		t.Fatalf("Failed to copy test file: %v", err)
	}

	ctx := context.Background()
	ds := &tests.MockDataStore{}
	mediaFileRepo := tests.CreateMockMediaFileRepo()
	genreRepo := &tests.MockedGenreRepo{}

	ds.MockedMediaFile = mediaFileRepo
	ds.MockedGenre = genreRepo

	lib := model.Library{
		ID:         1,
		Name:       "Nested Test Library",
		Path:       tempDir,
		LastScanAt: time.Time{},
	}

	scanner := NewTagScanner(ds, nil, &mockCacheWarmer{})
	progress := make(chan uint32, 100)

	_, err = scanner.Scan(ctx, lib, true, progress)
	close(progress)

	if err != nil {
		t.Fatalf("Scan failed: %v", err)
	}

	mediaFiles, err := mediaFileRepo.GetAll()
	if err != nil {
		t.Fatalf("Failed to get media files: %v", err)
	}

	if len(mediaFiles) == 0 {
		t.Errorf("Expected media files from nested directory to be found")
	}

	// Verify the file path is correct
	found := false
	for _, mf := range mediaFiles {
		if mf.Path == testFile {
			found = true
			break
		}
	}

	if !found {
		t.Errorf("Expected to find the nested test file in scanned results")
	}
}

